const item = $input.first();
const raw = String(item.json.chatInput ?? '').trim();
const sessionId = String(item.json.sessionId ?? 'default');
const staticData = $getWorkflowStaticData('global');
const key = `ocr_batch_${sessionId}`;

let pending = staticData[key];
if (pending?.createdAt && Date.now() - pending.createdAt > 60 * 60 * 1000) {
  delete staticData[key];
  pending = null;
}

const m = raw.match(/^folder:\s*(.+)$/i);
const pathStr = m ? m[1].trim() : raw;
const unix = pathStr.startsWith('/');
const win = /^[A-Za-z]:[\\/]/.test(pathStr);
const oneLine = !pathStr.includes('\n');
const explicit = Boolean(m);
const looksDir = explicit || (oneLine && (unix || win));

function isConfirm(s) {
  return /^(确认|确定|yes|ok|y|proceed|开始|继续)$/i.test(s);
}
function isCancel(s) {
  return /^(取消|cancel|no|否)$/i.test(s);
}

if (pending?.filePaths?.length) {
  if (isConfirm(raw)) {
    const paths = pending.filePaths.slice();
    const names = (pending.fileNames || []).slice();
    delete staticData[key];
    return [
      {
        json: {
          mode: 'folder_execute',
          filePaths: paths,
          fileNames: names,
          sessionId,
          chatInput: '批量 OCR',
        },
      },
    ];
  }
  if (isCancel(raw)) {
    delete staticData[key];
    const msg =
      '已取消批量 OCR。如需重新开始，请再次发送文件夹路径。';
    return [
      {
        json: {
          mode: 'plain_reply',
          output: msg,
          text: msg,
          sessionId,
        },
      },
    ];
  }
  if (!(looksDir && (unix || win))) {
    const n = pending.fileNames?.length ?? pending.filePaths.length;
    const msg = `仍有待确认的批量任务（共 **${n}** 张图）。请回复 **确认** 开始 OCR，**取消** 作废，或发送新的文件夹路径覆盖当前待办。`;
    return [
      {
        json: {
          mode: 'plain_reply',
          output: msg,
          text: msg,
          sessionId,
        },
      },
    ];
  }
}

if (looksDir && (unix || win)) {
  return [
    {
      json: {
        mode: 'folder_preview',
        folderPath: pathStr,
        sessionId,
        chatInput: pathStr,
      },
    },
  ];
}

const fallback =
  raw ||
  '请识别图片中的文字。若图中有红色矩形框，只输出红色框内的文字。';
return [
  {
    json: { mode: 'single', chatInput: fallback, sessionId },
    binary: item.binary,
  },
];

const fs = require('fs');
const path = require('path');

const input = $input.first().json;
const folderPath = input.folderPath;
const sessionId = String(input.sessionId ?? 'default');
if (!folderPath) {
  throw new Error('缺少 folderPath');
}
if (!fs.existsSync(folderPath)) {
  throw new Error('目录不存在或 n8n 进程无法访问: ' + folderPath);
}
if (!fs.statSync(folderPath).isDirectory()) {
  throw new Error('路径不是文件夹: ' + folderPath);
}

const exts = new Set([
  '.png',
  '.jpg',
  '.jpeg',
  '.webp',
  '.gif',
  '.bmp',
  '.tiff',
  '.tif',
]);
const names = fs
  .readdirSync(folderPath, { withFileTypes: true })
  .filter((d) => d.isFile())
  .map((d) => d.name);
const files = names
  .filter((n) => exts.has(path.extname(n).toLowerCase()))
  .sort()
  .map((n) => path.join(folderPath, n));

if (!files.length) {
  throw new Error('目录内没有支持的图片文件: ' + folderPath);
}

const fileNames = files.map((f) => path.basename(f));
const staticData = $getWorkflowStaticData('global');
const key = `ocr_batch_${sessionId}`;
staticData[key] = {
  filePaths: files,
  fileNames,
  folderPath,
  createdAt: Date.now(),
};

const maxShow = 40;
const shown = fileNames.slice(0, maxShow);
const more =
  fileNames.length > maxShow
    ? `\n… 另有 **${fileNames.length - maxShow}** 个文件未展开显示（仍会参与 OCR）。`
    : '';

const body =
  `### 待 OCR 审核\n\n` +
  `- **目录**：\`${folderPath}\`\n` +
  `- **图片总数**：**${fileNames.length}**\n\n` +
  `**文件名**（前 ${Math.min(maxShow, fileNames.length)} 个）：\n` +
  shown.map((n) => `- ${n}`).join('\n') +
  more +
  `\n\n---\n` +
  `请核对。确认无误后回复 **确认**（或 \`yes\` / \`ok\` / \`开始\`）开始 OCR；回复 **取消** 作废本次任务。\n` +
  `（约 **60 分钟**内有效，超时需重新发送路径。）`;

return [
  {
    json: {
      output: body,
      text: body,
      previewCount: fileNames.length,
    },
  },
];

const fs = require('fs');
const path = require('path');

const input = $input.first().json;
const sessionId = String(input.sessionId ?? 'default');
const filePaths = input.filePaths;
if (!Array.isArray(filePaths) || !filePaths.length) {
  throw new Error('缺少 filePaths');
}

const items = [];
for (const filePath of filePaths) {
  if (!fs.existsSync(filePath)) {
    throw new Error('文件不存在: ' + filePath);
  }
  const buf = fs.readFileSync(filePath);
  const base = path.basename(filePath);
  const ext = path.extname(base).toLowerCase();
  const mime =
    ext === '.png'
      ? 'image/png'
      : ext === '.jpg' || ext === '.jpeg'
        ? 'image/jpeg'
        : ext === '.webp'
          ? 'image/webp'
          : ext === '.gif'
            ? 'image/gif'
            : ext === '.bmp'
              ? 'image/bmp'
              : 'image/tiff';
  const binary = await this.helpers.prepareBinaryData(buf, base, mime);
  items.push({
    json: {
      chatInput:
        '请识别本图文字。若图中有红色矩形框，只输出红色框内的文字。',
      fileName: base,
      filePath,
      sessionId,
    },
    binary: { data: binary },
  });
}
return items;

const items = $input.all();
return items.map((item) => {
  const j = item.json;
  const t = j.output ?? j.text ?? '';
  return { json: { output: t, text: t } };
});

const all = $input.all();
if (all.length === 1) {
  return [all[0]];
}

function pickText(j) {
  if (j == null) return '';
  if (typeof j.output === 'string') return j.output;
  if (typeof j.text === 'string') return j.text;
  if (j.message && typeof j.message.content === 'string') return j.message.content;
  return JSON.stringify(j);
}

const parts = all.map((item, i) => {
  const name = item.json.fileName ?? `图像_${i + 1}`;
  return `### ${name}\n${pickText(item.json)}`;
});

const combined =
  `共 ${all.length} 张图，OCR 结果如下：\n\n` + parts.join('\n\n---\n\n');

return [{ json: { output: combined, text: combined, batchCount: all.length } }];
